<template>
  <button
    class="btn modal-play-button fs-small d-flex align-items-center px-space-xs pe-space-xxs"
    @click="handleButtonClick()"
    :disabled="disabled"
    :class="[getButtonClass, { disabled: disabled }]">
    <span v-if="buttonText" :class="getTextClass" class="me-space-xxs">{{
      buttonText
    }}</span>
    <img alt="videoButton" :src="VideoButton" />
  </button>
</template>
<script lang="ts" setup>
import { computed } from "vue";
import VideoButton from "./assets/Video-button.svg";
/**
 * Props for the ButtonPlayApollo component.
 */
export interface ButtonPlayApolloProps {
  /**
   * The text to display inside the button.
   */
  buttonText?: string;

  /**
   * The size of the button text. Default "medium"
   */
  buttonTextSize?: "small" | "medium" | "large" | "xl";

  /**
   * Color variant of the button text (e.g., "primary", "secondary", etc.).
   */
  buttonTextVariant?: string;

  /**
   * Color variant of the background (e.g., "primary", "secondary", etc.).
   */
  backgroundVariant?: string;
  /**
   * Disables the button .Default: false.
   */
  disabled?: boolean;
}
const props = withDefaults(defineProps<ButtonPlayApolloProps>(), {
  disabled: false,
  backgroundVariant: "dark-1",
});

const getButtonClass = computed(() => {
  return `btn-${props.backgroundVariant}`;
});

const getTextClass = computed(() => {
  return `fs-${props.buttonTextSize} text-${props.buttonTextVariant} `;
});

const handleButtonClick = () => {
  emits("ctaClick");
};
/**
 *  Emitters
 */
// event emitter from the component
const emits = defineEmits<{
  /**
   *  Emitted when cta clicked.
   */
  (e: "ctaClick"): void;
}>();
</script>
<style lang="scss">
.modal-play-button {
  img {
    border: 1px var(--rds-light-4, #d0d0d0) solid;
    border-radius: 50%;
    color: var(--rds-dark-3, #191919);
    background: var(--rds-white, #ffffff);
    opacity: 0.7;
    transition:
      transform 400ms,
      opacity 400ms;
  }
}
.disabled {
  cursor: not-allowed !important;
  pointer-events: none;
  user-select: none;
  opacity: 0.4;
}
</style>
